{
  "openapi": "3.0.0",
  "info": {
    "title": "RBCWires API Mini Spec",
    "version": "1.0.0"
  },
  "servers": [
    {
      "url": "https://prod02-apigateway.broadridge.com/usb/inbound",
      "description": "This API (known as the Reverse Flow) allows U.S Bank to access the Webhook URL confgured on Layer7 and will route to the GEMS API"
    }
  ],
  "paths": {
    "/gems/api/USBOutboundWireService": {
      "post": {
        "description": "The Reverse Flow starts at U.S. Bank to Layer7 which then routes to GEMS API.  This endpoint receives the U.S. Bank wire notification formats including NOR, NOF, NAK, ACK",
        "responses": {
          "200": {
            "description": "Successful Post to GEMS API"
          }
        },
        "security": [
          {
            "Client-Credentials": [
              "usb:gems:wires:write"
            ]
          }
        ]
      }
    },
    "/gems/api/healthCheck": {
      "get": {
        "description": "GEMS healthcheck endpoint for the reverse flow",
        "responses": {
          "200": {
            "description": "Successful get to the GEMS healthcheck endpoint"
          }
        },
        "security": [
          {
            "Client-Credentials": [
              "usb:gems:health:read"
            ]
          }
        ]
      }
    },
    "/health": {
      "get": {
        "description": "Gets the health of this API",
        "responses": {
          "200": {
            "description": "Successful Get of health endpoint"
          }
        },
        "security": [
          {
            "Client-Credentials": [
              "usb:gems:health:read"
            ]
          }
        ]
      }
    }
  }
}
